using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from other tests
            TestHelpers.DrainNotificationQueue();
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            _service.Dispose();
        }

        [Fact]
        public void SendAndReceive_SingleNotification_ReturnsCorrectNotification()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void SendAndReceive_MultipleNotifications_FIFO()
        {
            _service.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", "Second", EntityOperation.UPDATE);
            _service.SendNotification("Department", "3", "Third", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();
            var fourth = _service.ReceiveNotification();

            Assert.Equal("Student", first.EntityType);
            Assert.Equal("Course", second.EntityType);
            Assert.Equal("Department", third.EntityType);
            Assert.Null(fourth);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage_Create()
        {
            _service.SendNotification("Student", "1", "John", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("New Student 'John' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage_Update()
        {
            _service.SendNotification("Course", "5", "Math 101", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("Course 'Math 101' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage_Delete()
        {
            _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_GeneratesCorrectMessage_Create()
        {
            _service.SendNotification("Student", "5", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("New Student (ID: 5) has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_GeneratesCorrectMessage_Update()
        {
            _service.SendNotification("Course", "10", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("Course (ID: 10) has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_GeneratesCorrectMessage_Delete()
        {
            _service.SendNotification("Department", "7", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("Department (ID: 7) has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithUserName_SetsCreatedBy()
        {
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();

            Assert.Equal("admin", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();

            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.False(notification.IsRead);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void MarkAsRead_WithAnyId_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(999));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var svc = new NotificationService();
            var exception = Record.Exception(() => svc.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_CalledMultipleTimes_DoesNotThrow()
        {
            var svc = new NotificationService();
            svc.Dispose();
            var exception = Record.Exception(() => svc.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_DelegatesToFullOverload()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE, "testUser");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("testUser", notification.CreatedBy);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void QueueCap_EnforcedAt500()
        {
            // Send 510 notifications
            for (int i = 0; i < 510; i++)
            {
                _service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            // Drain and count
            int count = 0;
            while (_service.ReceiveNotification() != null)
            {
                count++;
            }

            Assert.True(count <= 500, $"Expected at most 500 notifications but got {count}");
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "New Student 'X' has been created")]
        [InlineData(EntityOperation.UPDATE, "Student 'X' has been updated")]
        [InlineData(EntityOperation.DELETE, "Student 'X' has been deleted")]
        public void SendNotification_AllOperations_GenerateExpectedMessages(EntityOperation operation, string expectedMessage)
        {
            _service.SendNotification("Student", "1", "X", operation);

            var notification = _service.ReceiveNotification();

            Assert.Equal(expectedMessage, notification.Message);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "New Course (ID: 1) has been created")]
        [InlineData(EntityOperation.UPDATE, "Course (ID: 1) has been updated")]
        [InlineData(EntityOperation.DELETE, "Course (ID: 1) has been deleted")]
        public void SendNotification_WithoutDisplayName_AllOperations(EntityOperation operation, string expectedMessage)
        {
            _service.SendNotification("Course", "1", operation);

            var notification = _service.ReceiveNotification();

            Assert.Equal(expectedMessage, notification.Message);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            var notification = _service.ReceiveNotification();

            Assert.Equal("System", notification.CreatedBy);
        }
    }
}

