using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<string> { "a", "b" };
            var list = new PaginatedList<string>(items, 10, 2, 5);
            Assert.Equal(2, list.PageIndex);
        }

        [Theory]
        [InlineData(10, 5, 2)]   // 10 items, 5 per page = 2 pages
        [InlineData(11, 5, 3)]   // 11 items, 5 per page = 3 pages (ceiling)
        [InlineData(0, 5, 0)]    // 0 items = 0 pages
        [InlineData(1, 5, 1)]    // 1 item, 5 per page = 1 page
        [InlineData(5, 5, 1)]    // exactly one page
        [InlineData(100, 10, 10)]
        public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
            Assert.Equal(expectedTotalPages, list.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 3, 1, 10);
            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Theory]
        [InlineData(1, false)]   // first page has no previous
        [InlineData(2, true)]    // second page has previous
        [InlineData(5, true)]
        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), 50, pageIndex, 10);
            Assert.Equal(expected, list.HasPreviousPage);
        }

        [Theory]
        [InlineData(1, 10, 5, true)]    // page 1 of 2 => has next
        [InlineData(2, 10, 5, false)]   // page 2 of 2 => no next
        [InlineData(1, 5, 5, false)]    // page 1 of 1 => no next
        [InlineData(3, 50, 10, true)]   // page 3 of 5 => has next
        [InlineData(5, 50, 10, false)]  // page 5 of 5 => no next
        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int count, int pageSize, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), count, pageIndex, pageSize);
            Assert.Equal(expected, list.HasNextPage);
        }

        [Fact]
        public void Constructor_EmptyItems_CreatesEmptyList()
        {
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);
            Assert.Empty(list);
            Assert.Equal(0, list.TotalPages);
            Assert.Equal(1, list.PageIndex);
        }

        [Fact]
        public void Create_ReturnsCorrectPageOfItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(new[] { 6, 7, 8, 9, 10 }, result.ToArray());
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 3);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(new[] { 1, 2, 3 }, result.ToArray());
            Assert.False(result.HasPreviousPage);
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 7).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 3);

            Assert.Equal(3, result.PageIndex);
            Assert.Single(result); // only item 7
            Assert.Equal(7, result[0]);
            Assert.True(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_SingleItem_SinglePage()
        {
            var source = new[] { 42 }.AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Single(result);
            Assert.Equal(42, result[0]);
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_LargePageSize_ReturnsAllItems()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 100);

            Assert.Equal(5, result.Count);
            Assert.Equal(1, result.TotalPages);
        }
    }
}

