using System;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateContext();
            _controller = new NotificationsController(_context);
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var jsonResult = result as JsonResult;
            Assert.NotNull(jsonResult);
            var value = jsonResult.Value;
            // Use reflection to check anonymous type properties
            var successProp = value.GetType().GetProperty("success");
            var countProp = value.GetType().GetProperty("count");
            Assert.True((bool)successProp.GetValue(value));
            Assert.Equal(0, (int)countProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            var svc = new ContosoUniversity.Services.NotificationService();
            svc.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
            svc.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);

            var result = _controller.GetNotifications() as JsonResult;

            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            var countProp = value.GetType().GetProperty("count");
            Assert.True((bool)successProp.GetValue(value));
            Assert.Equal(2, (int)countProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            var svc = new ContosoUniversity.Services.NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications() as JsonResult;

            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.Equal(10, (int)countProp.GetValue(value));
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1) as JsonResult;

            Assert.NotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void MarkAsRead_AnyId_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(999) as JsonResult;

            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void GetNotifications_ConsumesFromQueue_NotAvailableAgain()
        {
            var svc = new ContosoUniversity.Services.NotificationService();
            svc.SendNotification("Student", "1", EntityOperation.CREATE);

            _controller.GetNotifications();

            // Second call should have no notifications left
            var result2 = _controller.GetNotifications() as JsonResult;
            var value = result2.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.Equal(0, (int)countProp.GetValue(value));
        }
    }
}

using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateContext();
            _controller = new HomeController(_context);
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
        }

        [Fact]
        public void About_NoStudents_ReturnsEmptyList()
        {
            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(result.Model);
            Assert.Empty(model);
        }

        [Fact]
        public void About_WithStudents_ReturnsGroupedByEnrollmentDate()
        {
            var date1 = new DateTime(2024, 9, 1);
            var date2 = new DateTime(2023, 9, 1);
            _context.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "1", EnrollmentDate = date1 },
                new Student { LastName = "B", FirstMidName = "2", EnrollmentDate = date1 },
                new Student { LastName = "C", FirstMidName = "3", EnrollmentDate = date2 }
            );
            _context.SaveChanges();

            var result = _controller.About() as ViewResult;

            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(result.Model);
            Assert.Equal(2, model.Count);

            var group1 = model.FirstOrDefault(g => g.EnrollmentDate == date1);
            Assert.NotNull(group1);
            Assert.Equal(2, group1.StudentCount);

            var group2 = model.FirstOrDefault(g => g.EnrollmentDate == date2);
            Assert.NotNull(group2);
            Assert.Equal(1, group2.StudentCount);
        }

        [Fact]
        public void Contact_SetsViewBagMessage()
        {
            var result = _controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", result.ViewData["Message"]);
        }

        [Fact]
        public void Error_ReturnsView()
        {
            var result = _controller.Error() as ViewResult;
            Assert.NotNull(result);
        }

        [Fact]
        public void Unauthorized_SetsViewBagMessage()
        {
            var result = _controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("You don't have permission to access this resource.", result.ViewData["Message"]);
        }
    }
}

